SELECT f.id, f.user_id, f.music_id, f.parent_id, f.content, f.create_time, u.username, u.nickname, u.avatar, COALESCE(like_stats.like_count, 0) as like_count, COALESCE(reply_stats.reply_count, 0) as reply_count, CASE WHEN #{currentUserId} IS NOT NULL AND user_like.id IS NOT NULL THEN 1 ELSE 0 END as is_liked FROM feedback f LEFT JOIN user u ON f.user_id = u.id LEFT JOIN ( SELECT comment_id, COUNT(*) as like_count FROM comment_like GROUP BY comment_id ) like_stats ON f.id = like_stats.comment_id LEFT JOIN ( SELECT parent_id, COUNT(*) as reply_count FROM feedback WHERE type = 'COMMENT' AND parent_id IS NOT NULL GROUP BY parent_id ) reply_stats ON f.id = reply_stats.parent_id
LEFT JOIN comment_like user_like ON f.id = user_like.comment_id AND user_like.user_id = #{currentUserId}
LEFT JOIN comment_like user_like ON 1 = 0
WHERE f.music_id = #{musicId} AND f.type = 'COMMENT' AND (f.parent_id IS NULL OR f.parent_id = 0) ORDER BY f.create_time DESC LIMIT #{offset}, #{limit}

SELECT f.id, f.user_id, f.music_id, f.parent_id, f.content, f.create_time, u.username, u.nickname, u.avatar, COALESCE(like_stats.like_count, 0) as like_count, COALESCE(reply_stats.reply_count, 0) as reply_count, CASE WHEN #{currentUserId} IS NOT NULL AND user_like.id IS NOT NULL THEN 1 ELSE 0 END as is_liked FROM feedback f LEFT JOIN user u ON f.user_id = u.id LEFT JOIN ( SELECT comment_id, COUNT(*) as like_count FROM comment_like GROUP BY comment_id ) like_stats ON f.id = like_stats.comment_id LEFT JOIN ( SELECT parent_id, COUNT(*) as reply_count FROM feedback WHERE type = 'COMMENT' AND parent_id IS NOT NULL GROUP BY parent_id ) reply_stats ON f.id = reply_stats.parent_id
LEFT JOIN comment_like user_like ON f.id = user_like.comment_id AND user_like.user_id = #{currentUserId}
LEFT JOIN comment_like user_like ON 1 = 0
WHERE f.music_id = #{musicId} AND f.type = 'COMMENT' AND (f.parent_id IS NULL OR f.parent_id = 0) ORDER BY like_count DESC, f.create_time DESC LIMIT #{offset}, #{limit}

SELECT f.id, f.user_id, f.music_id, f.parent_id, f.content, f.create_time, u.username, u.nickname, u.avatar, COALESCE(like_stats.like_count, 0) as like_count, CASE WHEN #{currentUserId} IS NOT NULL AND user_like.id IS NOT NULL THEN 1 ELSE 0 END as is_liked FROM feedback f LEFT JOIN user u ON f.user_id = u.id LEFT JOIN ( SELECT comment_id, COUNT(*) as like_count FROM comment_like GROUP BY comment_id ) like_stats ON f.id = like_stats.comment_id
LEFT JOIN comment_like user_like ON f.id = user_like.comment_id AND user_like.user_id = #{currentUserId}
LEFT JOIN comment_like user_like ON 1 = 0
WHERE f.parent_id = #{commentId} AND f.type = 'COMMENT' ORDER BY f.create_time ASC LIMIT #{limit}

SELECT m.id, f.id AS favorite_id, m.title, m.artist, m.album, m.file_url, m.preview_url, m.duration, m.genre, m.lyrics, m.cover_url, m.play_count, m.like_count, m.status, f.create_time AS favorite_time FROM feedback f INNER JOIN music m ON f.music_id = m.id WHERE f.user_id = #{userId} AND f.type = 'FAVORITE'
AND (m.title LIKE CONCAT('%', #{keyword}, '%') OR m.artist LIKE CONCAT('%', #{keyword}, '%') OR m.album LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY f.create_time DESC LIMIT #{offset}, #{limit}

SELECT f.id, f.user_id, f.music_id, f.parent_id, f.content, f.create_time, u.username, u.nickname, u.avatar, COALESCE(like_stats.like_count, 0) AS like_count, COALESCE(reply_stats.reply_count, 0) AS reply_count, CASE WHEN #{currentUserId} IS NOT NULL AND user_like.id IS NOT NULL THEN 1 ELSE 0 END AS is_liked, m.title AS music_title, m.artist AS music_artist, m.cover_url AS music_cover_url FROM feedback f LEFT JOIN user u ON f.user_id = u.id LEFT JOIN music m ON f.music_id = m.id LEFT JOIN ( SELECT comment_id, COUNT(*) AS like_count FROM comment_like GROUP BY comment_id ) like_stats ON f.id = like_stats.comment_id LEFT JOIN ( SELECT parent_id, COUNT(*) AS reply_count FROM feedback WHERE type = 'COMMENT' AND parent_id IS NOT NULL GROUP BY parent_id ) reply_stats ON f.id = reply_stats.parent_id
LEFT JOIN comment_like user_like ON f.id = user_like.comment_id AND user_like.user_id = #{currentUserId}
LEFT JOIN comment_like user_like ON 1 = 0
WHERE f.type = 'COMMENT' AND (f.parent_id IS NULL OR f.parent_id = 0) AND f.music_id IS NOT NULL
AND (f.content LIKE CONCAT('%', #{keyword}, '%') OR u.username LIKE CONCAT('%', #{keyword}, '%') OR u.nickname LIKE CONCAT('%', #{keyword}, '%') OR m.title LIKE CONCAT('%', #{keyword}, '%') OR m.artist LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY f.create_time DESC LIMIT #{offset}, #{limit}

